sql:
SELECT waste_type 
FROM waste_segregation_data 
WHERE municipality_id = 0;

SELECT vehicle_name, capacity, fuel_type, maintenance_schedule
FROM transportation_vehicles
WHERE vehicle_id >= 5 AND capacity > 500;

SELECT m.name AS municipality_name, wcd.waste_type, wcd.quantity
FROM municipalities m
JOIN waste_collection_data wcd ON m.municipality_id = wcd.municipality_id;

SELECT municipality_id, name
FROM municipalities
ORDER BY name ASC;

SELECT DISTINCT m.name 
FROM municipalities m
INNER JOIN waste_segregation_data wsd ON m.municipality_id = wsd.municipality_id;

SELECT m.name AS city_name, h.household_id, h.waste_generation
FROM municipalities m
INNER JOIN households h ON m.municipality_id = h.municipality_id;

SELECT municipality_id, COUNT(*) AS Number_of_Non_Residential_Areas
FROM non_residential_areas
GROUP BY municipality_id;

SELECT waste_type, quantity
FROM waste_collection_data
WHERE municipality_id = 123;

SELECT LOWER(method_name) AS lower_case_method_name, MIN(cost) AS min_cost
FROM waste_collection_methods
GROUP BY method_name;
